function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    const max_w = edges.length > 0 ? edges[edges.length - 1][2] : 0;
    let low = 0, high = max_w;

    while (low < high) {
        const mid = Math.floor((low + high) / 2);
        const components = countComponents(mid, edges, n);
        if (components <= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

function countComponents(x, edges, n) {
    const parent = Array(n).fill(0).map((_, i) => i);
    const rank = Array(n).fill(1);

    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u, v) {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                if (rank[rootU] === rank[rootV]) {
                    rank[rootU]++;
                }
            }
        }
    }

    for (const [u, v, w] of edges) {
        if (w <= x) {
            union(u, v);
        }
    }

    const roots = new Set();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }
    return roots.size;
}

