import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long low = 0;
        long high = 0;
        if (edges.length > 0) {
            high = edges[edges.length - 1][2];
        }
        while (low < high) {
            long mid = (low + high) / 2;
            int components = countComponents(mid, edges, (int) n);
            if (components <= k) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private static int countComponents(long x, long[][] edges, int n) {
        DSU dsu = new DSU(n);
        for (long[] edge : edges) {
            if (edge[2] <= x) {
                dsu.union((int) edge[0], (int) edge[1]);
            }
        }
        Set<Integer> roots = new HashSet<>();
        for (int i = 0; i < n; i++) {
            roots.add(dsu.find(i));
        }
        return roots.size();
    }

    private static class DSU {
        private int[] parent;
        private int[] rank;

        public DSU(int n) {
            parent = new int[n];
            rank = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX != rootY) {
                if (rank[rootX] < rank[rootY]) {
                    parent[rootX] = rootY;
                } else {
                    parent[rootY] = rootX;
                    if (rank[rootX] == rank[rootY]) {
                        rank[rootX]++;
                    }
                }
            }
        }
    }
}
