```java
import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long max_w = 0;
        if (edges.length > 0) {
            max_w = edges[edges.length - 1][2];
        }
        long low = 0, high = max_w;
        while (low < high) {
            long mid = (low + high) / 2;
            long components = countComponents(mid, edges, n);
            if (components <= k) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private static long countComponents(long x, long[][] edges, long n) {
        long[] parent = new long[(int) n];
        long[] rank = new long[(int) n];
        for (long i = 0; i < n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long w = edge[2];
            if (w <= x) {
                long rootU = find(parent, u);
                long rootV = find(parent, v);
                if (rootU != rootV) {
                    if (rank[rootU] < rank[rootV]) {
                        parent[rootU] = rootV;
                    } else {
                        parent[rootV] = rootU;
                        if (rank[rootU] == rank[rootV]) {
                            rank[rootU]++;
                        }
                    }
                }
            }
        }
        Set<Long> roots = new HashSet<>();
        for (long i = 0; i < n; i++) {
            roots.add(find(parent, i));
        }
        return roots.size();
    }

    private static long find(long[] parent, long u) {
        while (parent[u] != u) {
            parent[u] = parent[parent[u]]; // path compression
            u = parent[u];
        }
        return u;
    }
}
