}

function countComponents(x, edges, n) {
    const parent = Array(n).fill(0).map((_, i) => i);
    const rank = Array(n).fill(1);

    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u, v) {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                if (rank[rootU] === rank[rootV]) {
                    rank[rootU]++;
                }
            }
        }
    }

    for (const [u, v, w] of edges) {
        if (w <= x) {
            union(u, v);
        }
    }

    const roots = new Set();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }
    return roots.size;
}
